// ── Icon component ──────────────────────────────────────────────────────────

#[component]
pub fn Icon(kind: IconKind, #[prop(default = 20)] size: u32) -> impl IntoView {
    let style = format!("width: {}px; height: {}px;", size, size);

    view! {
        <svg
            viewBox="0 0 40 40"
            fill="currentColor"
            xmlns="http://www.w3.org/2000/svg"
            aria-hidden="true"
            style=style
        >
            <path d=kind.path_data() />
        </svg>
    }
}
